import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v) { val = v; }
    }

    static Node build(int[] pre, int pl, int pr, int[] in, int il, int ir, Map<Integer,Integer> map) {
        if (pl > pr) return null;
        int rootVal = pre[pl];
        int idx = map.get(rootVal);
        int leftSize = idx - il;
        Node node = new Node(rootVal);
        node.left = build(pre, pl + 1, pl + leftSize, in, il, idx - 1, map);
        node.right = build(pre, pl + leftSize + 1, pr, in, idx + 1, ir, map);
        return node;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder all = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            all.append(line).append(' ');
        }
        StringTokenizer st = new StringTokenizer(all.toString());
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(st.nextToken());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(st.nextToken());
            int[] pre = new int[N];
            int[] in = new int[N];
            for (int i = 0; i < N; i++) pre[i] = Integer.parseInt(st.nextToken());
            for (int i = 0; i < N; i++) in[i] = Integer.parseInt(st.nextToken());
            Map<Integer,Integer> map = new HashMap<>(N * 2);
            for (int i = 0; i < N; i++) map.put(in[i], i);
            Node root = build(pre, 0, N - 1, in, 0, N - 1, map);
            out.append("Well Done!");
            if (tc != T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

